/**
 * Webhook notification adapter.
 *
 * Implements NotificationAdapter for the 'webhook' channel.
 * Formats the notification payload as JSON and POSTs it to a configured URL.
 * Uses a WebhookTransport abstraction so the actual HTTP mechanism
 * can be swapped (e.g., fetch, axios, test stub) without changing this adapter.
 */

import type {
  NotificationAdapter,
  NotificationChannel,
  NotificationPayload,
  NotificationResult,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * The JSON body sent to the webhook endpoint.
 */
export interface WebhookRequestBody {
  type: string;
  recipient: string;
  subject: string;
  body: string;
  metadata?: Record<string, unknown>;
  timestamp: string;
}

/**
 * Abstraction for the actual HTTP POST mechanism.
 * Implement this to integrate with a real HTTP client.
 */
export interface WebhookTransport {
  post(url: string, body: WebhookRequestBody, headers: Record<string, string>): Promise<{ statusCode: number }>;
}

/**
 * Default in-memory transport for development and testing.
 * Stores posted requests in an array for inspection.
 */
export class InMemoryWebhookTransport implements WebhookTransport {
  private requests: Array<{ url: string; body: WebhookRequestBody; headers: Record<string, string>; postedAt: Date }> = [];

  async post(url: string, body: WebhookRequestBody, headers: Record<string, string>): Promise<{ statusCode: number }> {
    this.requests.push({ url, body, headers, postedAt: new Date() });
    return { statusCode: 200 };
  }

  getRequests(): Array<{ url: string; body: WebhookRequestBody; headers: Record<string, string>; postedAt: Date }> {
    return [...this.requests];
  }

  clear(): void {
    this.requests = [];
  }
}

/**
 * Webhook configuration options.
 */
export interface WebhookAdapterConfig {
  url: string;
  secret?: string;
  transport?: WebhookTransport;
}

function isValidUrl(url: string): boolean {
  try {
    const parsed = new URL(url);
    return parsed.protocol === 'http:' || parsed.protocol === 'https:';
  } catch {
    return false;
  }
}

export class WebhookAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'webhook';
  private logger = new Logger('WebhookAdapter');
  private url: string;
  private secret?: string;
  private transport: WebhookTransport;

  constructor(config: WebhookAdapterConfig) {
    if (!isValidUrl(config.url)) {
      throw new Error(`Invalid webhook URL: ${config.url}`);
    }
    this.url = config.url;
    this.secret = config.secret;
    this.transport = config.transport ?? new InMemoryWebhookTransport();
  }

  /**
   * Format a notification payload into the webhook JSON body.
   */
  formatPayload(payload: NotificationPayload): WebhookRequestBody {
    return {
      type: payload.type,
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      metadata: payload.metadata,
      timestamp: new Date().toISOString(),
    };
  }

  /**
   * Build request headers for the webhook POST.
   */
  private buildHeaders(): Record<string, string> {
    const headers: Record<string, string> = {
      'Content-Type': 'application/json',
    };
    if (this.secret) {
      headers['X-Webhook-Secret'] = this.secret;
    }
    return headers;
  }

  /**
   * Send a notification via webhook POST.
   * Formats the payload as JSON and POSTs it to the configured URL.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    const body = this.formatPayload(payload);
    const headers = this.buildHeaders();

    this.logger.info(`Sending webhook to ${this.url} for ${payload.type}`);

    try {
      const result = await this.transport.post(this.url, body, headers);

      if (result.statusCode >= 200 && result.statusCode < 300) {
        this.logger.info(`Webhook delivered successfully (${result.statusCode})`);
        return {
          success: true,
          notificationId: '',
          channel: this.channel,
        };
      }

      this.logger.warn(`Webhook returned non-success status: ${result.statusCode}`);
      return {
        success: false,
        notificationId: '',
        channel: this.channel,
        error: `Webhook returned status ${result.statusCode}`,
      };
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : String(err);
      this.logger.error(`Failed to deliver webhook to ${this.url}: ${errorMessage}`);

      return {
        success: false,
        notificationId: '',
        channel: this.channel,
        error: `Webhook delivery failed: ${errorMessage}`,
      };
    }
  }

  /**
   * Get the underlying transport (useful for testing with InMemoryWebhookTransport).
   */
  getTransport(): WebhookTransport {
    return this.transport;
  }
}

